proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_tla_forall_leads_to_equality_intensional(a_to_p: spec_fn(int) -> TempPred<int>, q: TempPred<int>)
    ensures
        tla_forall(|a: int| a_to_p(a).leads_to(q)) == tla_exists(a_to_p).leads_to(q),
{
    tla_forall_leads_to_equality1::<int, int>(a_to_p, q);
}

proof fn phi_3_spec_entails_tla_forall_intensional_bridge(spec: TempPred<int>, a_to_p: spec_fn(int) -> TempPred<int>)
    requires
        forall |a: int| spec.entails(#[trigger] a_to_p(a)),
    ensures
        spec.entails(tla_forall(a_to_p)),
{
    spec_entails_tla_forall::<int, int>(spec, a_to_p);
}

proof fn phi_4_leads_to_exists_false_antecedent(spec: TempPred<int>, q: TempPred<int>)
    requires
        forall |a: int| spec.entails((|a: int| TempPred::<int>::new(|ex: Execution<int>| false))(a).leads_to(q)),
    ensures
        spec.entails(tla_exists(|a: int| TempPred::<int>::new(|ex: Execution<int>| false)).leads_to(q)),
{
    leads_to_exists_intro::<int, int>(spec, |a: int| TempPred::new(|ex: Execution<int>| false), q);
}

proof fn phi_5_leads_to_exists_any_spec(spec: TempPred<int>, a_to_p: spec_fn(int) -> TempPred<int>, q: TempPred<int>)
